mapper.select:
SELECT SM.SERVICE_ID, SM.CARID_NO, SM.CAR_NO, SM.COMPANY_ID, TC.COMPANY_NM, TO_CHAR(SM.REQUEST_DT, 'YYYYMMDD') AS REQUEST_DT, SM.PROC_ST FROM TR_SCRAP_MILEAGE SM, TM_COMPANY TC WHERE SM.COMPANY_ID = TC.COMPANY_ID(+) AND SM.REQUEST_DT BETWEEN TO_DATE(#{START_DT} || '00:00:00', 'YYYYMMDDHH24:MI:SS') AND TO_DATE(#{END_DT} || '23:59:59', 'YYYYMMDDHH24:MI:SS')
AND SM.COMPANY_ID = #{COMPANY_ID}
ORDER BY SM.REQUEST_DT DESC

SELECT CS.CARID_NO, CS.CAR_NM, CS.SISE_AMT, TO_CHAR(CS.STD_DT, 'YYYYMMDD') AS STD_DT FROM TM_CAR_SISE CS WHERE 1=1
AND CS.CARID_NO = #{CARID_NO}
ORDER BY CS.STD_DT DESC

SELECT CP.CARID_NO, CP.PRICE_AMT, TO_CHAR(CP.STD_DT, 'YYYYMMDD') AS STD_DT FROM TM_CAR_365PRICE CP WHERE 1=1
AND CP.CARID_NO = #{CARID_NO}
ORDER BY CP.STD_DT DESC
